```class Solution {
    public int minChanges(int[] nums, int k) {
        int result = 0;
        for (int i = 0; i < nums.length; i++) {
            int sum = 0;
            for (int j = i + 1; j < i + k && j < nums.length; j++) {
                sum ^= nums[j];
            }
            result = Math.max(result, sum);
        }
        return result;
    }
}
